mapper.select:
select id, 
from article
where id = #{id}

mapper.update:
update article
set status = #{status},
published_at = case
when #{status} = 'published' and published_at is null
then #{updatedAt}
else published_at
end,
updated_at = #{updatedAt}
where id = #{id}

update article
set is_top = #{isTop},
updated_at = #{updatedAt}
where id = #{id}

update article
set is_recommend = #{isRecommend},
updated_at = #{updatedAt}
where id = #{id}

